// ─── Seed runner ────────────────────────────────────────────────────────────
async function upsertBatch(table, rows, conflictCol, label) {
  if (!rows.length) { console.log(`  ⚠ ${label}: no rows`); return 0 }
  const { error } = await supabase.from(table).upsert(rows, { onConflict: conflictCol, ignoreDuplicates: false })
  if (error) {
    console.error(`  ✗ ${label}: ${error.message}`)
    return 0
  }
  console.log(`  ✓ ${label}: ${rows.length} rows upserted`)
  return rows.length
}

async function seed() {
  console.log('\n🌱  seed-marketplace — populating new tables\n')
  const results = {}

  results.investment_verticals = await upsertBatch('investment_verticals', VERTICALS, 'slug', 'investment_verticals (15 verticals)')

  // listing_plans has no unique constraint by default — upsert on vertical+plan_name
  // Use delete-then-insert pattern to keep it idempotent
  const { error: delPlansErr } = await supabase.from('listing_plans').delete().neq('id', 0)
  if (delPlansErr) console.warn('  ⚠ listing_plans clear:', delPlansErr.message)
  const { error: insPlansErr } = await supabase.from('listing_plans').insert(LISTING_PLANS)
  if (insPlansErr) { console.error('  ✗ listing_plans:', insPlansErr.message); results.listing_plans = 0 }
  else { console.log(`  ✓ listing_plans: ${LISTING_PLANS.length} rows inserted`); results.listing_plans = LISTING_PLANS.length }

  results.investment_listings = await upsertBatch('investment_listings', LISTINGS, 'slug', `investment_listings (${LISTINGS.length} listings)`)

  results.fi_tax_brackets = await upsertBatch('fi_tax_brackets', FI_TAX_BRACKETS, 'tax_year,taxpayer_type,income_from', 'fi_tax_brackets (8 brackets)')
  results.fi_dta_countries = await upsertBatch('fi_dta_countries', FI_DTA_COUNTRIES, 'country_code', 'fi_dta_countries (42 countries)')
  results.fi_dasp_rates = await upsertBatch('fi_dasp_rates', FI_DASP_RATES, 'component_type,visa_category', 'fi_dasp_rates (4 rates)')
  results.fi_withholding_rates = await upsertBatch('fi_withholding_rates', FI_WITHHOLDING_RATES, 'income_type', 'fi_withholding_rates (8 types)')
  results.fi_property_rules = await upsertBatch('fi_property_rules', FI_PROPERTY_RULES, 'rule_key', 'fi_property_rules (9 rules)')

  const categoriesWithTimestamp = FI_DATA_CATEGORIES.map(c => ({ ...c, last_verified_at: new Date().toISOString() }))
  results.fi_data_categories = await upsertBatch('fi_data_categories', categoriesWithTimestamp, 'category_key', 'fi_data_categories (5 categories)')

  const total = Object.values(results).reduce((a, b) => a + b, 0)
  console.log(`\n✅  Done — ${total} total rows seeded across ${Object.keys(results).length} tables`)
  console.log('   Results:', results)
}

seed().catch(err => { console.error('Fatal:', err); process.exit(1) })
